1	const BASE_PRICES: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
11	const SUBSEQUENT_CONTRACT_DISCOUNT_PERCENT = 15;
12	const FIXED_FEE = 5;
13	const ALIKE_COMPONENT_BLOCK_SIZE = 3;
14	const ALIKE_COMPONENT_BLOCK_PRICE = 60;
15	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
16	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATIO = 0.5;
17	const CLAIM_DEDUCTIBLE = 100;
18	
19	function applyFirstInsuranceSurcharge(amount: number): number {
20	  return Math.ceil((amount * (100 + FIRST_INSURANCE_SURCHARGE_PERCENT)) / 100);
21	}
22	
23	function applySubsequentContractDiscount(amount: number): number {
24	  return Math.ceil((amount * (100 - SUBSEQUENT_CONTRACT_DISCOUNT_PERCENT)) / 100);
25	}
26	
27	function countByType(items: { type: string }[]): Record<string, number> {
28	  return items.reduce<Record<string, number>>((counts, item) => {
29	    counts[item.type] = (counts[item.type] ?? 0) + 1;
30	    return counts;
31	  }, {});
32	}
33	
34	function priceForType(type: string, count: number): number {
35	  const blocks = Math.floor(count / ALIKE_COMPONENT_BLOCK_SIZE);
36	  const leftover = count % ALIKE_COMPONENT_BLOCK_SIZE;
37	  return blocks * ALIKE_COMPONENT_BLOCK_PRICE + leftover * BASE_PRICES[type];
38	}
39	
40	function quoteBasePrice(items: { type: string }[]): number {
41	  const counts = countByType(items);
42	  return Object.entries(counts).reduce(
43	    (total, [type, count]) => total + priceForType(type, count),
44	    0
45	  );
46	}
47	
48	function applyRatioIf(
49	  condition: boolean,
50	  basePrice: number,
51	  numerator: number,
52	  denominator: number
53	): number {
54	  return condition ? Math.ceil((basePrice * numerator) / denominator) : basePrice;
55	}
56	
57	function applyCursedSurcharge(items: { cursed: boolean }[], basePrice: number): number {
58	  const hasCursed = items.some((item) => item.cursed);
59	  return applyRatioIf(hasCursed, basePrice, 3, 2);
60	}
61	
62	function applyEnchantedSurcharge(items: { enchantment: number }[], basePrice: number): number {
63	  const hasHighEnchant = items.some((item) => item.enchantment >= 5);
64	  return applyRatioIf(hasHighEnchant, basePrice, 13, 10);
65	}
66	
67	function applyLoyaltyDiscount(yearsWithMHPCO: number, basePrice: number): number {
68	  return applyRatioIf(yearsWithMHPCO >= 2, basePrice, 8, 10);
69	}
70	
71	function computeClaimPayout(scenario: any, step: any): number {
72	  const policyStep = scenario.steps[step.policy];
73	  const damage = step.damages[0];
74	  const item = policyStep.items.find((i: any) => i.type === damage.itemType);
75	  const reimbursement =
76	    item.enchantment >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
77	      ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATIO
78	      : 0;
79	  return Math.max(0, reimbursement - CLAIM_DEDUCTIBLE);
80	}
81	
82	export function runScenario(scenario: any): unknown {
83	  const results: ({ premium: number } | { payout: number })[] = [];
84	  for (const step of scenario.steps) {
85	    if (step.op === "claim") {
86	      results.push({ payout: computeClaimPayout(scenario, step) });
87	      continue;
88	    }
89	    const items = step.items;
90	    const basePrice = quoteBasePrice(items);
91	    const withCursed = applyCursedSurcharge(items, basePrice);
92	    const withEnchanted = applyEnchantedSurcharge(items, withCursed);
93	    const withLoyalty = applyLoyaltyDiscount(scenario.customer.yearsWithMHPCO, withEnchanted);
94	    const isFirstQuote = results.length === 0;
95	    const withContractAdjustment = isFirstQuote
96	      ? applyFirstInsuranceSurcharge(withLoyalty)
97	      : applySubsequentContractDiscount(withLoyalty);
98	    const premium = withContractAdjustment + FIXED_FEE;
99	    results.push({ premium });
100	  }
101	  return { results };
102	}
